//! Example implementation of lulu-logs v2.0.0 streamable format
//! 
//! This demonstrates:
//! - The unified LogRecord structure
//! - Length-prefixed streamable format
//! - Multiple transport support (File, TCP, Memory)
//! - Migration from v1.4.0

use flatbuffers::{FlatBufferBuilder, WIPOffset};
use std::fs::{File, OpenOptions};
use std::io::{self, Read, Write, Seek, SeekFrom};
use std::path::Path;

// ============================================================================
// Generated-like types (would normally be generated by flatc)
// ============================================================================

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(u8)]
pub enum LogLevel {
    Trace = 0,
    Debug = 1,
    Info = 2,
    Warn = 3,
    Error = 4,
    Fatal = 5,
}

impl Default for LogLevel {
    fn default() -> Self {
        LogLevel::Info
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(u32)]
pub enum DataType {
    // Primitive types
    String = 0,
    Int32 = 1,
    Int64 = 2,
    Float32 = 3,
    Float64 = 4,
    Bool = 5,
    Json = 6,
    Bytes = 7,
    
    // Specialized binary types
    NetPacket = 8,
    SerialChunk = 9,
    
    // Span types
    SpanBeg = 1000,
    SpanEnd = 1001,
    ScenarioBeg = 1002,
    ScenarioEnd = 1003,
    StepBeg = 1004,
    StepEnd = 1005,
}

// ============================================================================
// LogRecord - The unified structure for v2.0.0
// ============================================================================

/// LogRecord represents a single log entry in lulu-logs v2.0.0
/// This combines the functionality of both LogEntry (v1) and LogRecord (v1 export)
#[derive(Debug, Clone, PartialEq)]
pub struct LogRecord {
    /// Topic path WITHOUT the "lulu/" prefix
    /// Example: "psu/power-supply/channel-1/voltage"
    pub topic: String,
    
    /// ISO 8601 UTC timestamp with millisecond precision
    /// Example: "2026-02-26T14:30:00.123Z"
    pub timestamp: String,
    
    /// Severity level (defaults to Info)
    pub level: LogLevel,
    
    /// Type descriptor for the data field
    pub data_type: DataType,
    
    /// The actual data value as a raw binary buffer
    pub data: Vec<u8>,
}

impl LogRecord {
    /// Create a new LogRecord
    pub fn new(
        topic: impl Into<String>,
        timestamp: impl Into<String>,
        level: LogLevel,
        data_type: DataType,
        data: impl Into<Vec<u8>>,
    ) -> Self {
        Self {
            topic: topic.into(),
            timestamp: timestamp.into(),
            level,
            data_type,
            data: data.into(),
        }
    }
    
    /// Helper to create a string log record
    pub fn string(
        topic: impl Into<String>,
        timestamp: impl Into<String>,
        level: LogLevel,
        value: impl Into<String>,
    ) -> Self {
        Self::new(
            topic,
            timestamp,
            level,
            DataType::String,
            value.into().into_bytes(),
        )
    }
    
    /// Helper to create a JSON log record
    pub fn json(
        topic: impl Into<String>,
        timestamp: impl Into<String>,
        level: LogLevel,
        value: impl serde::Serialize,
    ) -> io::Result<Self> {
        let json_bytes = serde_json::to_vec(&value)
            .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;
        
        Ok(Self::new(
            topic,
            timestamp,
            level,
            DataType::Json,
            json_bytes,
        ))
    }
    
    /// Helper to create a float64 log record
    pub fn float64(
        topic: impl Into<String>,
        timestamp: impl Into<String>,
        level: LogLevel,
        value: f64,
    ) -> Self {
        Self::new(
            topic,
            timestamp,
            level,
            DataType::Float64,
            value.to_le_bytes().to_vec(),
        )
    }
    
    /// Helper to create an int32 log record
    pub fn int32(
        topic: impl Into<String>,
        timestamp: impl Into<String>,
        level: LogLevel,
        value: i32,
    ) -> Self {
        Self::new(
            topic,
            timestamp,
            level,
            DataType::Int32,
            value.to_le_bytes().to_vec(),
        )
    }
}

// ============================================================================
// FlatBuffers serialization (simulated - in real code, use generated code)
// ============================================================================

/// Simulate FlatBuffers serialization for LogRecord
/// In real implementation, this would be generated by flatc
fn serialize_log_record(record: &LogRecord) -> Vec<u8> {
    let mut builder = FlatBufferBuilder::new();
    
    // Create string offsets
    let topic_offset = builder.create_string(&record.topic);
    let timestamp_offset = builder.create_string(&record.timestamp);
    
    // Create data vector
    let data_offset = builder.create_vector(&record.data);
    
    // Create the LogRecord table (simulated structure)
    // In real code: LogRecord::create(&mut builder, &LogRecordArgs { ... })
    let mut table = Vec::new();
    
    // Write fields (simplified - real FlatBuffers uses vtable)
    // Field 0: topic
    table.extend_from_slice(&topic_offset.to_le_bytes());
    // Field 1: timestamp  
    table.extend_from_slice(&timestamp_offset.to_le_bytes());
    // Field 2: level (1 byte, but aligned)
    table.push(record.level as u8);
    table.extend_from_slice(&[0, 0, 0]); // padding
    // Field 3: data_type (4 bytes)
    table.extend_from_slice(&(record.data_type as u32).to_le_bytes());
    // Field 4: data
    table.extend_from_slice(&data_offset.to_le_bytes());
    
    // Create the table in the builder
    let table_offset = builder.create_vector(&table);
    
    // Finish the buffer
    builder.finish(table_offset, None);
    
    builder.finished_data().to_vec()
}

